insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002', 'Reviewed irrigation schedules across both sites this week. Site A is on track; Site B needs a revised watering window before the heat picks up next month.', 'normal', '2026-01-10T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', 'Concerned about Site A pump capacity going into the new plot expansion. Have not raised this with the client yet — want engineering numbers first.', 'restricted', '2026-01-12T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000003', 'Weekly walkthrough of Site A north plot completed. Soil moisture readings within expected range across all rows.', 'normal', '2026-01-14T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000003', 'Foreman crew on north plot seems short-staffed for the upcoming harvest. Not sure yet whether to flag this upward or try to resolve it locally first.', 'restricted', '2026-01-15T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000006', 'South plot expansion prep underway. Marked out new rows for next season, coordinating with the seed supplier on timing.', 'normal', '2026-01-16T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000006', 'Budget for south plot expansion is tighter than expected. Have not decided how to handle the shortfall — may need to phase the rollout.', 'restricted', '2026-01-17T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000004', 'تفقدت خط الري الرئيسي في القطعة الشمالية اليوم. لاحظت انخفاضاً في الضغط عند الساعة العاشرة صباحاً، وبعد الفحص وجدت أن أحد الصمامات لم يُغلق بشكل كامل. قمت بإصلاحه مؤقتاً لكن يجب استبداله قبل نهاية الأسبوع.', 'normal', '2026-01-18T07:30:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000008', '10000000-0000-0000-0000-000000000004', 'اجتمعت مع فريق الـ irrigation اليوم لمناقشة مشكلة الـ pressure drop المتكررة. أعتقد أن السبب الحقيقي هو أن المضخة القديمة لم تعد كافية لحجم القطعة الجديدة. لم أخبر المشرف بعد لأنني أريد التأكد أولاً قبل أن أثير الموضوع.', 'restricted', '2026-01-19T07:45:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000009', '10000000-0000-0000-0000-000000000005', 'Finished trellis repairs on rows 12 through 18. Two posts replaced, wire tension redone across the whole section.', 'normal', '2026-01-20T08:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-00000000000a', '10000000-0000-0000-0000-000000000007', 'Noticed a pump pressure drop again on the south line after we brought the new plot online. Same symptom as before the upgrade last quarter.', 'normal', '2026-01-21T08:15:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-00000000000b', '10000000-0000-0000-0000-000000000007', 'Not confident the new hire on south plot is following the watering checklist. Watching for another week before saying anything.', 'restricted', '2026-01-22T08:20:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-00000000000c', '10000000-0000-0000-0000-000000000008', 'Site B quarterly review complete. Overall yield tracking slightly above projection.', 'normal', '2026-02-01T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-00000000000d', '10000000-0000-0000-0000-000000000008', 'Site B client relationship has been tense since the delayed shipment last month. Handling carefully, not escalating yet.', 'restricted', '2026-02-02T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-00000000000e', '10000000-0000-0000-0000-000000000009', 'Completed intake inspection on this week’s deliveries. All logged, two items flagged for the supplier.', 'normal', '2026-02-05T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-00000000000f', '10000000-0000-0000-0000-000000000009', 'Considering swapping suppliers after this quarter given the recurring quality issues, but not ready to make the call yet.', 'restricted', '2026-02-06T09:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000010', '10000000-0000-0000-0000-00000000000a', 'استلمنا اليوم شحنة الـ seeds الجديدة من المورد. الكمية مطابقة للطلب لكن بعض الأكياس كانت مبللة قليلاً بسبب المطر أثناء النقل. وضعتها في مكان جاف للتأكد من عدم تلفها.', 'normal', '2026-02-08T07:30:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000011', '10000000-0000-0000-0000-00000000000a', 'لدي شك بأن بعض البذور التي استلمناها الأسبوع الماضي ليست من نفس الصنف المطلوب. لم أتحقق من هذا رسمياً بعد لأنني لا أريد اتهام المورد قبل التأكد الكامل. سأراقب الإنبات في الأيام القادمة.', 'restricted', '2026-02-09T07:45:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000012', '10000000-0000-0000-0000-00000000000b', 'Weeding pass completed on rows 1 through 9. Ground cover looking healthy overall.', 'normal', '2026-02-10T08:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000013', '10000000-0000-0000-0000-00000000000d', 'Routine equipment check completed, nothing to flag this week.', 'normal', '2026-02-12T08:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000014', '10000000-0000-0000-0000-00000000000f', 'First week on site, getting familiar with the plot layout and existing schedules.', 'normal', '2026-02-14T08:00:00Z', null);
insert into journal_entries (id, author_id, body, sensitivity, created_at, soft_deleted_at) values ('20000000-0000-0000-0000-000000000015', '10000000-0000-0000-0000-000000000004', 'Draft note about a pump issue, written and then deleted the same day after re-checking — this entry simulates a soft-deleted row whose vectors were left behind by the delete-vs-embed race (spec §1.5).', 'normal', '2026-02-15T08:00:00Z', '2026-02-15T08:05:00Z');
insert into wiki_entries (id, owner_id, created_at) values ('30000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000002', '2026-01-25T10:00:00Z');
insert into wiki_entries (id, owner_id, created_at) values ('30000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000004', '2026-01-26T10:00:00Z');
insert into wiki_entries (id, owner_id, created_at) values ('30000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000009', '2026-02-11T10:00:00Z');
insert into wiki_entry_versions (id, wiki_entry_id, title, body, sensitivity, created_by, created_at) values ('31000000-0000-0000-0000-000000000001', '30000000-0000-0000-0000-000000000001', 'Irrigation Line Maintenance Protocol', 'Standard checklist for main-line irrigation maintenance: inspect valves monthly, flush filters quarterly, and log any pressure anomalies within 24 hours of observation.', 'normal', '10000000-0000-0000-0000-000000000002', '2026-01-25T10:00:00Z');
insert into wiki_entry_versions (id, wiki_entry_id, title, body, sensitivity, created_by, created_at) values ('31000000-0000-0000-0000-000000000002', '30000000-0000-0000-0000-000000000002', 'Site A Pump Capacity Notes', 'Internal notes on Site A pump sizing relative to plot expansion plans, pending formal engineering review.', 'restricted', '10000000-0000-0000-0000-000000000004', '2026-01-26T10:00:00Z');
insert into wiki_entry_versions (id, wiki_entry_id, title, body, sensitivity, created_by, created_at) values ('31000000-0000-0000-0000-000000000003', '30000000-0000-0000-0000-000000000003', 'Seed Intake Inspection Checklist', 'Checklist for inspecting incoming seed shipments: verify variety against order, check for moisture damage, log any discrepancies before storage.', 'normal', '10000000-0000-0000-0000-000000000009', '2026-02-11T10:00:00Z');
insert into qa_threads (id, asker_id, question, status, visibility_scope, created_at) values ('40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000007', 'Has anyone seen a pump pressure drop like this before after adding a new plot?', 'answered', 'organization', '2026-01-23T09:00:00Z');
insert into qa_threads (id, asker_id, question, status, visibility_scope, created_at) values ('40000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-00000000000b', 'What''s the standard procedure for logging a damaged seed shipment?', 'open', 'organization', '2026-02-13T09:00:00Z');
insert into qa_answers (id, thread_id, answerer_id, created_at) values ('41000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', '2026-01-24T09:00:00Z');
insert into qa_answer_versions (id, answer_id, body, created_at) values ('42000000-0000-0000-0000-000000000001', '41000000-0000-0000-0000-000000000001', 'Yes — Site A had a similar issue after the new plot was added last quarter. The old pump could not keep up with the added draw. We upgraded to a higher-capacity pump and the pressure stabilized within a week.', '2026-01-24T09:00:00Z');
